  ('dietitian-moex-01320', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '重症病人營養支持時，血糖變異程度與臨床預後相關，下列那一個血糖區間是目前建議預後較好 且併發症較少者？', '["80-110mg/dL", "110-150mg/dL", "150-180mg/dL", "180-220mg/dL"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01321', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '80歲老太太因急性腎盂腎炎併發敗血症及呼吸衰竭，經急救後入加護病房。入院前一週身高153 公分，體重55公斤。入院時意識不清，有氣管插管；同時放置鼻胃管，給予腸道營養。灌食後第', '["應將床 頭抬高30-45度，以減少吸入性肺炎的可能性", "考慮給予促胃腸蠕動劑（prokineticagents）", "考慮灌食配方中加膳食纖維以促進腸胃蠕動", "考慮使用連續式管灌或小腸灌食  ⑤停止管灌 餵食，考慮開始全靜脈營養，以減少吸入性肺炎的可能性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01322', 'dietitian', 'dietitian-moex-110-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對於肥胖重症病患開始使用低熱量高蛋白質的營養支持時，熱量建議為何？', '["一般估計熱量需求的50-70%", "一般估計熱量需求的25-35%", "15-20kcal/kg實際體重", "15-20kcal/kg理想體重"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "397cf22c480a", "answer_pdf_sha1": "18a33b1169b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
